import Page from 'components/Page';
import React from 'react';
import {
  Button,
  Card,
  CardBody,
  CardHeader,
  Col,
  Form,
  FormFeedback,
  FormGroup,
  FormText,
  Input,
  Label,
  Row,
  Alert,
  Table,
} from 'reactstrap';
import states from "../api/states";
import yearsofex from "../api/yearsofex";
import { unEnrollSubject, findSubjects, findTerms, findStudents, } from "../api/api";
import AsyncStorage from '@callstack/async-storage';
import conf from "../api/config";
import PageSpinner from 'components/PageSpinner';
import MUIDataTable from "mui-datatables";
class UnenrollStudentPage extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
          subject : 'nn',
          student : '',
          status : 'nn',
          xtoken:'',
          msg: '',
          error: '',
          preload:false,
          downloadFile:true,
          data: [],
          subjects:[],
          students:[],
        };
        AsyncStorage.getItem(conf.secret)
        .then((results) => {
          if( results !== null )
          {
            let obje_results = JSON.parse(results);
            this.setState({
              ...this.state,
              xtoken : obje_results.user.token,
            });
            findSubjects(obje_results.user.token).then((response) => {
                this.setState({
                    ...this.state,
                    subjects:response.data,
                });
            }).catch((respError) => {});
            findStudents(obje_results.user.token).then((response) => {
                this.setState({
                    ...this.state,
                    students:response.data,
                });
            }).catch((respError) => {});
          }
        })
        .catch((error) => {
          console.log('storage error', error);
        });
    }
    componentDidMount() {
    }

    
    handleSubjectInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, subject: v,});
    }
    handleStudentInput = (event) => {
        const v = event.target.value;
        this.setState({...this.state, student: v,});
    }
    handlestatusInput = (event) => {
      const v = event.target.value;
      this.setState({...this.state, status: v,});
    }
    handleSaveChanges = () => {
        // console.log('so far', this.state);
        this.setState({
          ...this.state,
          preload:true,
        });
        unEnrollSubject(this.state.xtoken, this.state)
        .then((response) => {
            // console.log('so_far', response);
            if( response.status === 200)
            {
                this.setState({
                    ...this.state,
                    subject:'nn',
                    student:'',
                    status:'nn',
                    msg: response.message,
                    data: response.data,
                    error: '',
                    preload:false,
                });
                // this.forceUpdate();
            }
            else
            {
                this.setState({
                    ...this.state,
                    error: response.message,
                    msg: '',
                    preload:false,
                });
            }
        })
        .catch((error) => {
            this.setState({
                ...this.state,
                error: 'Connection error occured',
                preload:false,
            });
            console.log('error', error);
        });
    }
    render() {
      return (
        <Page title="Enrollments - Unenroll" breadcrumbs={[{ name: 'Unenroll', active: true }]}>
          <Row>
            <Col xl={12} lg={12} md={12}>
              <Card>
                <CardHeader>Unenroll Suject {this.state.preload && (<PageSpinner/>)} </CardHeader>
                {this.state.error.length > 0 && (
                    <Alert color="danger">{this.state.error}</Alert>
                )}
                {this.state.msg.length > 0 && (
                    <Alert color="success">{this.state.msg}</Alert>
                )}
              </Card>
            </Col>
          </Row>
          <Row>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                <Form>
                    <FormGroup>
                      <Label for="exampleSelect">Subject *</Label>
                      <Input onChange={this.handleSubjectInput} value={this.state.subject} defaultValue={this.state.subject} type="select" name="frm">
                        <option value="nn" disabled={true}>Select Subject</option>
                        {this.state.subjects.map((stt, idx) => (
                            <option value={stt.id}>{stt.label}</option>
                        ))}
                      </Input>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                    <FormGroup>
                      <Label for="exampleSelect">Student Admission No.*</Label>
                      <Input onChange={this.handleStudentInput}
                        type="number" 
                        value={this.state.student}
                        name="frm"
                        placeholder=""
                      />
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
            <Col xl={3} lg={12} md={12}>
              <Card>
                <CardBody>
                  <Form>
                    <FormGroup check row>
                      <Col sm={{ size: 10, offset: 2 }}>
                        <Button type="button" onClick={this.handleSaveChanges}>Unenroll</Button>
                      </Col>
                    </FormGroup>
                  </Form>
                </CardBody>
              </Card>
            </Col>
          </Row>
        </Page>
      );
    }
}
export default UnenrollStudentPage;
